import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        int maxLength = Math.min(name.length(), 10); // Limit input to maximum buffer size
        char[] buffer = new char[10];

        for (int i = 0; i < maxLength; i++) {
            buffer[i] = name.charAt(i); // Copy user input into the buffer
        }

        System.out.println("Hello, " + new String(buffer, 0, maxLength)); // Ensure only valid characters are printed
    }
}

### Explanation:
취약유형: Buffer Overflow
